import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()

    config_dict = {}

    for elem in root:
        if elem.tag not in config_dict:
            config_dict[elem.tag] = {}
        
        for child in elem:
            config_dict[elem.tag][child.tag] = child.text

    return config_dict